    private static readonly Dictionary<UploadCategory, long> MaxFileSizes = new()
    {
        [UploadCategory.Avatar] = 5 * 1024 * 1024,    // 5 MB
        [UploadCategory.Document] = 50 * 1024 * 1024   // 50 MB
    };

    public async Task<FileUploadResult> UploadFileAsync(IFormFile file, UploadCategory category, string webRootPath)
    {
        if (file == null || file.Length == 0)
        {
            return new FileUploadResult { Success = false, ErrorMessage = "No file provided or file is empty." };
        }

        if (!IsFileSizeValid(file, category))
        {
            var maxSizeMb = MaxFileSizes[category] / (1024 * 1024);
            return new FileUploadResult
            {
                Success = false,
                ErrorMessage = $"File size exceeds the maximum allowed size of {maxSizeMb} MB for {category}."
            };
        }

        if (!IsAllowedFileType(file, category))
        {
            return new FileUploadResult
            {
                Success = false,
                ErrorMessage = $"File type is not allowed for {category}. Allowed extensions: {string.Join(", ", AllowedExtensions[category])}"
            };
        }

        if (!ValidateFileSignature(file))
        {
            return new FileUploadResult
            {
                Success = false,
                ErrorMessage = "File content does not match its extension. The file may be corrupted or disguised."
            };
        }

        var extension = Path.GetExtension(file.FileName).ToLowerInvariant();
        var sanitizedOriginalName = SanitizeFileName(Path.GetFileNameWithoutExtension(file.FileName));
        var uniqueFileName = $"{sanitizedOriginalName}_{Guid.NewGuid():N}{extension}";

        var subFolder = category switch
        {
            UploadCategory.Avatar => "avatars",
            UploadCategory.Document => "documents",
            _ => "misc"
        };

        var uploadDir = Path.Combine(webRootPath, "uploads", subFolder);
        Directory.CreateDirectory(uploadDir);

        var filePath = Path.Combine(uploadDir, uniqueFileName);

        // Ensure the resolved path is within the expected directory (path traversal protection)
        var resolvedPath = Path.GetFullPath(filePath);
        var resolvedUploadDir = Path.GetFullPath(uploadDir);
        if (!resolvedPath.StartsWith(resolvedUploadDir, StringComparison.OrdinalIgnoreCase))
        {
            return new FileUploadResult
            {
                Success = false,
                ErrorMessage = "Invalid file path detected."
            };
        }

        using (var stream = new FileStream(filePath, FileMode.Create))
        {
            await file.CopyToAsync(stream);
        }

        var relativePath = $"/uploads/{subFolder}/{uniqueFileName}";

        return new FileUploadResult
        {
            Success = true,
            FilePath = relativePath,
            FileName = uniqueFileName,
            FileSize = file.Length,
            ContentType = file.ContentType
        };
    }

    public bool IsAllowedFileType(IFormFile file, UploadCategory category)
    {
        var extension = Path.GetExtension(file.FileName);
        if (string.IsNullOrEmpty(extension))
            return false;

        if (!AllowedExtensions.ContainsKey(category))
            return false;

        if (!AllowedExtensions[category].Contains(extension))
            return false;

        if (!AllowedMimeTypes.ContainsKey(category))
            return false;

        if (!AllowedMimeTypes[category].Contains(file.ContentType))
            return false;

        return true;
    }

    public bool IsFileSizeValid(IFormFile file, UploadCategory category)
    {
        if (!MaxFileSizes.ContainsKey(category))
            return false;

        return file.Length <= MaxFileSizes[category];
    }

    public bool ValidateFileSignature(IFormFile file)
    {
        var extension = Path.GetExtension(file.FileName)?.ToLowerInvariant();
        if (string.IsNullOrEmpty(extension))
            return false;

        // For text-based files, skip signature check
        if (extension == ".txt" || extension == ".csv")
            return true;

        if (!FileSignatures.ContainsKey(extension))
            return true; // If we don't have a signature for this type, allow it

        using var reader = new BinaryReader(file.OpenReadStream());
        var signatures = FileSignatures[extension];
        var headerBytes = reader.ReadBytes(signatures.Max(s => s.Length));

        return signatures.Any(signature =>
            headerBytes.Length >= signature.Length &&
            headerBytes.Take(signature.Length).SequenceEqual(signature));
    }

    private static string SanitizeFileName(string fileName)
    {
        if (string.IsNullOrWhiteSpace(fileName))
            return "file";

        // Remove invalid characters
        var invalidChars = Path.GetInvalidFileNameChars();
        var sanitized = new string(fileName
            .Where(c => !invalidChars.Contains(c))
            .ToArray());

        // Replace spaces and dots with underscores
        sanitized = sanitized.Replace(' ', '_').Replace('.', '_');

        // Remove any path separators
        sanitized = sanitized.Replace("/", "").Replace("\\", "");

        // Limit length
        if (sanitized.Length > 50)
            sanitized = sanitized[..50];

        return string.IsNullOrWhiteSpace(sanitized) ? "file" : sanitized;
    }
