[ApiController]
[Route("api/[controller]")]
public class FileUploadController : ControllerBase
{
    private readonly IFileUploadService _fileUploadService;
    private readonly IWebHostEnvironment _environment;

    public FileUploadController(IFileUploadService fileUploadService, IWebHostEnvironment environment)
    {
        _fileUploadService = fileUploadService;
        _environment = environment;
    }

    /// <summary>
    /// Upload a user avatar image (max 5 MB, images only)
    /// </summary>
    [HttpPost("avatar")]
    [RequestSizeLimit(5 * 1024 * 1024)]
    public async Task<IActionResult> UploadAvatar(IFormFile file)
    {
        if (file == null)
            return BadRequest(new FileUploadResult { Success = false, ErrorMessage = "No file provided." });

        var webRootPath = _environment.WebRootPath ?? Path.Combine(Directory.GetCurrentDirectory(), "wwwroot");
        var result = await _fileUploadService.UploadFileAsync(file, UploadCategory.Avatar, webRootPath);

        if (!result.Success)
            return BadRequest(result);

        return Ok(result);
    }

    /// <summary>
    /// Upload a document (max 50 MB, images/PDFs/Office documents)
    /// </summary>
    [HttpPost("document")]
    [RequestSizeLimit(50 * 1024 * 1024)]
    public async Task<IActionResult> UploadDocument(IFormFile file)
    {
        if (file == null)
            return BadRequest(new FileUploadResult { Success = false, ErrorMessage = "No file provided." });

        var webRootPath = _environment.WebRootPath ?? Path.Combine(Directory.GetCurrentDirectory(), "wwwroot");
        var result = await _fileUploadService.UploadFileAsync(file, UploadCategory.Document, webRootPath);

        if (!result.Success)
            return BadRequest(result);

        return Ok(result);
    }

    /// <summary>
    /// Upload multiple documents at once (max 10 files)
    /// </summary>
    [HttpPost("documents")]
    [RequestSizeLimit(50 * 1024 * 1024)]
    public async Task<IActionResult> UploadMultipleDocuments(List<IFormFile> files)
    {
        if (files == null || files.Count == 0)
            return BadRequest(new { Success = false, ErrorMessage = "No files provided." });

        if (files.Count > 10)
            return BadRequest(new { Success = false, ErrorMessage = "Maximum 10 files allowed per upload." });

        var webRootPath = _environment.WebRootPath ?? Path.Combine(Directory.GetCurrentDirectory(), "wwwroot");
        var results = new List<FileUploadResult>();

        foreach (var file in files)
        {
            var result = await _fileUploadService.UploadFileAsync(file, UploadCategory.Document, webRootPath);
            results.Add(result);
        }

        var allSuccessful = results.All(r => r.Success);

        return Ok(new
        {
            Success = allSuccessful,
            TotalFiles = files.Count,
            SuccessfulUploads = results.Count(r => r.Success),
            FailedUploads = results.Count(r => !r.Success),
            Results = results
        });
    }

    /// <summary>
    /// Generic upload endpoint with category specification
    /// </summary>
    [HttpPost("upload")]
    [RequestSizeLimit(50 * 1024 * 1024)]
    public async Task<IActionResult> Upload([FromForm] FileUploadRequest request)
    {
        if (!ModelState.IsValid)
            return BadRequest(ModelState);

        if (request.File == null)
            return BadRequest(new FileUploadResult { Success = false, ErrorMessage = "No file provided." });

        var webRootPath = _environment.WebRootPath ?? Path.Combine(Directory.GetCurrentDirectory(), "wwwroot");
        var result = await _fileUploadService.UploadFileAsync(request.File, request.Category, webRootPath);

        if (!result.Success)
            return BadRequest(result);

        return Ok(result);
    }
}